  1	import * as _ from 'lodash-es';
  2	import * as React from 'react';
  3	import { useTranslation } from 'react-i18next';
  4	import { useDispatch } from 'react-redux';
  5	import {
  6	  Button,
  7	  DatePicker,
  8	  Flex,
  9	  FlexItem,
 10	  Modal,
 11	  ModalVariant,
 12	  TimePicker,
 13	} from '@patternfly/react-core';
 14	
 15	import { dashboardsSetEndTime, dashboardsSetTimespan, Perspective } from '../../../actions/observe';
 16	
 17	import { QueryParams } from '../../query-params';
 18	import { useIsPerses } from './useIsPerses';
 19	import { NumberParam, useQueryParam } from 'use-query-params';
 20	
 21	const zeroPad = (number: number) => (number < 10 ? `0${number}` : number);
 22	
 23	// Get YYYY-MM-DD date string for a date object
 24	const toISODateString = (date: Date): string =>
 25	  `${date.getFullYear()}-${zeroPad(date.getMonth() + 1)}-${zeroPad(date.getDate())}`;
 26	
 27	// Get HH:MM time string for a date object
 28	const toISOTimeString = (date: Date): string =>
 29	  new Intl.DateTimeFormat(
 30	    'en',
 31	    // TODO: TypeScript 3 doesn't allow the `hourCycle` attribute so use "as any" until we upgrade
 32	    { hour: 'numeric', minute: 'numeric', hourCycle: 'h23' } as any,
 33	  ).format(date);
 34	
 35	type CustomTimeRangeModalProps = {
 36	  perspective: Perspective;
 37	  isOpen: boolean;
 38	  setClosed: () => void;
 39	  timespan?: number;
 40	  endTime?: number;
 41	};
 42	
 43	const CustomTimeRangeModal: React.FC<CustomTimeRangeModalProps> = ({
 44	  perspective,
 45	  isOpen,
 46	  setClosed,
 47	  timespan,
 48	  endTime,
 49	}) => {
 50	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
 51	  const isPerses = useIsPerses();
 52	  const [, setEndTime] = useQueryParam(QueryParams.EndTime, NumberParam);
 53	  const [, setTimeRange] = useQueryParam(QueryParams.TimeRange, NumberParam);
 54	
 55	  const dispatch = useDispatch();
 56	
 57	  // If a time is already set in Redux, default to that, otherwise default to a time range that
 58	  // covers all of today
 59	  const now = new Date();
 60	  const defaultFrom = endTime && timespan ? new Date(endTime - timespan) : undefined;
 61	  const [fromDate, setFromDate] = React.useState(toISODateString(defaultFrom ?? now));
 62	  const [fromTime, setFromTime] = React.useState(
 63	    defaultFrom ? toISOTimeString(defaultFrom) : '00:00',
 64	  );
 65	  const [toDate, setToDate] = React.useState(toISODateString(endTime ? new Date(endTime) : now));
 66	  const [toTime, setToTime] = React.useState(
 67	    endTime ? toISOTimeString(new Date(endTime)) : '23:59',
 68	  );
 69	
 70	  const submit: React.MouseEventHandler<HTMLButtonElement> = () => {
 71	    const from = Date.parse(`${fromDate} ${fromTime}`);
 72	    const to = Date.parse(`${toDate} ${toTime}`);
 73	    if (_.isInteger(from) && _.isInteger(to)) {
 74	      if (!isPerses) {
 75	        dispatch(dashboardsSetEndTime(to, perspective));
 76	        dispatch(dashboardsSetTimespan(to - from, perspective));
 77	      }
 78	      setEndTime(Number(to.toString()));
 79	      setTimeRange(Number((to - from).toString()));
 80	      setClosed();
 81	    }
 82	  };
 83	
 84	  return (
 85	    <Modal
 86	      hasNoBodyWrapper
 87	      isOpen={isOpen}
 88	      position="top"
 89	      showClose={false}
 90	      title={t('Custom time range')}
 91	      variant={ModalVariant.small}
 92	    >
 93	      <Flex className="custom-time-range-modal" direction={{ default: 'column' }}>
 94	        <FlexItem spacer={{ default: 'spacerNone' }}>
 95	          <label>{t('From')}</label>
 96	        </FlexItem>
 97	        <Flex>
 98	          <FlexItem>
 99	            <DatePicker onChange={(event, str) => setFromDate(str)} value={fromDate} />
100	          </FlexItem>
101	          <FlexItem>
102	            <TimePicker is24Hour onChange={(event, text) => setFromTime(text)} time={fromTime} />
103	          </FlexItem>
104	        </Flex>
105	        <FlexItem spacer={{ default: 'spacerNone' }}>
106	          <label>{t('To')}</label>
107	        </FlexItem>
108	        <Flex>
109	          <FlexItem>
110	            <DatePicker onChange={(event, str) => setToDate(str)} value={toDate} />
111	          </FlexItem>
112	          <FlexItem>
113	            <TimePicker is24Hour onChange={(event, text) => setToTime(text)} time={toTime} />
114	          </FlexItem>
115	        </Flex>
116	        <Flex className="custom-time-range-modal-footer">
117	          <FlexItem align={{ default: 'alignRight' }}>
118	            <Button variant="secondary" onClick={setClosed}>
119	              {t('Cancel')}
120	            </Button>
121	          </FlexItem>
122	          <FlexItem>
123	            <Button variant="primary" onClick={submit}>
124	              {t('Save')}
125	            </Button>
126	          </FlexItem>
127	        </Flex>
128	      </Flex>
129	    </Modal>
130	  );
131	};
132	
133	export default CustomTimeRangeModal;

